        truncation: true,
    });

    // Process images
    const { pixel_values } = await this.processor(preparedImages);

    // Run model with BOTH text and image inputs
    const output = await this.model({ ...text_inputs, pixel_values });

    // Apply activation function based on model type
    const function_to_apply =
        this.model.config.model_type === 'siglip'
            ? batch => batch.sigmoid().data
            : batch => softmax(batch.data);

    // Compare each image with each label
    const toReturn = [];
    for (const batch of output.logits_per_image) {
        const probs = function_to_apply(batch);
        const result = [...probs].map((x, i) => ({
            score: x,
            label: candidate_labels[i]
        }));
        result.sort((a, b) => b.score - a.score);
        toReturn.push(result);
    }

    return isBatched ? toReturn : toReturn[0];
}
```

**Key Characteristics:**
- Passes **both text and image inputs** to model in single call: `this.model({ ...text_inputs, pixel_values })`
- Uses special output field `logits_per_image` from model
- Supports different activation functions (sigmoid for SigLIP, softmax for CLIP)
- Returns scores + labels sorted by score descending

