#### D. **ZeroShotAudioClassificationPipeline** (Audio + Text)

**File:** `src/pipelines.js`, **Lines 1577-1628**

**Constructor:** Takes `TextAudioPipelineConstructorArgs`

**_call Method Pattern:**
```javascript
async _call(audio, candidate_labels, {
    hypothesis_template = "This is a sound of {}."
} = {}) {
    const single = !Array.isArray(audio);
    if (single) {
        audio = [audio];
    }

    // Create text prompts
    const texts = candidate_labels.map(
        x => hypothesis_template.replace('{}', x)
    );

    // Tokenize text
    const text_inputs = this.tokenizer(texts, {
        padding: true,
        truncation: true,
    });

    // Prepare audio
    const sampling_rate = this.processor.feature_extractor.config.sampling_rate;
    const preparedAudios = await prepareAudios(audio, sampling_rate);

    const toReturn = [];
    for (const aud of preparedAudios) {
        // Process audio
        const audio_inputs = await this.processor(aud);

        // Run model with BOTH text and audio inputs
        const output = await this.model({ ...text_inputs, ...audio_inputs });

        // Compute softmax per audio
        const probs = softmax(output.logits_per_audio.data);

        toReturn.push([...probs].map((x, i) => ({
            score: x,
            label: candidate_labels[i]
        })));
    }
    return single ? toReturn[0] : toReturn;
}
```

**Key Characteristics:**
- Uses `this.processor.feature_extractor.config.sampling_rate` to get audio config
- Spreads both text and audio inputs: `this.model({ ...text_inputs, ...audio_inputs })`
- Uses `logits_per_audio` output field
- Handles batched/single audio inputs

