19	
20	        if (text) {
21	            const [height, width] = image_inputs.pixel_values.dims.slice(-2);
22	
23	            const { image_token, image_break_token, image_end_token, patch_size, spatial_merge_size } = this.config;
24	            const real_patch_size = patch_size * spatial_merge_size;
25	            const num_height_tokens = Math.floor(height / real_patch_size);
26	            const num_width_tokens = Math.floor(width / real_patch_size);
27	
28	            text = structuredClone(text); // Avoid modifying the original text input
29	            if (!Array.isArray(text)) {
30	                text = [text];
31	            }
32	            for (let i = 0; i < text.length; ++i) {
33	                const width_tokens = image_token.repeat(num_width_tokens);
34	                const row = width_tokens + image_break_token;
35	                const finalRow = width_tokens + image_end_token;
36	                const full = row.repeat(num_height_tokens - 1) + finalRow;
37	                text[i] = text[i].replace(image_token, full);
38	            }
39	        }
40	        
41	        const text_inputs = text ? this.tokenizer(text, kwargs) : {};
